svg.script:
// Sample N points from the SVG path element for physics simulation
const pathEl = document.getElementById('orbit-path');
const dot    = document.getElementById('dot');
const TOTAL  = pathEl.getTotalLength();
const N      = 800; // sample resolution

// Pre-sample all points along the path
const pts = [];
for (let i = 0; i < N; i++) {
  const p = pathEl.getPointAtLength((i / N) * TOTAL);
  pts.push({ x: p.x, y: p.y });
}

// Get position & tangent at fractional index f ∈ [0, 1)
function getState(f) {
  const raw = ((f % 1) + 1) % 1;
  const s   = raw * TOTAL;
  const p0  = pathEl.getPointAtLength(s);
  const eps = 0.5;
  const p1  = pathEl.getPointAtLength((s + eps) % TOTAL);
  const dx  = p1.x - p0.x;
  const dy  = p1.y - p0.y;
  const len = Math.hypot(dx, dy) || 1;
  return {
    x:  p0.x, y: p0.y,
    ty: dy / len,          // y-component of normalised tangent
    dsdf: TOTAL            // ds/df  (constant: s = f * TOTAL)
  };
}

// Physics
const G      = 260;  // gravity px/s²
const MIN    = 18;   // minimum speed px/s

// Start at the original dot position (top-right of the path)
// That corresponds roughly to f=0 (path starts at M point)
let f     = 0;       // parametric position [0, 1)
let speed = 40;      // px/s along path
let last  = null;

function frame(ts) {
  if (!last) last = ts;
  const dt = Math.min((ts - last) / 1000, 0.04);
  last = ts;

  // Sub-step integration (4 steps per frame)
  for (let s = 0; s < 4; s++) {
    const st  = getState(f);
    // Tangential acceleration: gravity component along tangent
    // ty > 0 → tangent points down → ball accelerates
    speed += G * st.ty * (dt / 4);
    if (speed < MIN) speed = MIN;
    // Advance fraction: df = (speed px/s) / (TOTAL px/cycle) * dt
    f += (speed / TOTAL) * (dt / 4);
  }
  f = ((f % 1) + 1) % 1;

  const st = getState(f);
  dot.setAttribute('cx', st.x.toFixed(3));
  dot.setAttribute('cy', st.y.toFixed(3));

  requestAnimationFrame(frame);
}

requestAnimationFrame(frame);
